"use client";

import Link from "next/link";
import { useEffect, useState } from "react";
import { ScenarioCard } from "@/components/ScenarioCard";
import { Button } from "@/components/ui/button";
import { createEmptyTiberoConfig } from "@/lib/tibero-config";
import type { GlobalSettings, Scenario, TiberoConfig } from "@/lib/types";

export default function HomePage() {
  const [scenarios, setScenarios] = useState<Scenario[]>([]);
  const [settings, setSettings] = useState<TiberoConfig>(createEmptyTiberoConfig());
  const [settingsMessage, setSettingsMessage] = useState<string | null>(null);
  const [settingsLoading, setSettingsLoading] = useState(false);

  async function loadScenarios() {
    const response = await fetch("/api/scenarios");
    const payload = (await response.json()) as { success: boolean; data?: Scenario[] };

    if (payload.success && payload.data) {
      setScenarios(payload.data);
    }
  }

  async function loadSettings() {
    const response = await fetch("/api/settings/tibero");
    const payload = (await response.json()) as { success: boolean; data?: GlobalSettings | null };

    if (payload.success && payload.data?.tiberoConfig) {
      setSettings(payload.data.tiberoConfig);
    }
  }

  async function handleDelete(id: string) {
    if (!window.confirm("삭제하시겠습니까?")) {
      return;
    }

    await fetch(`/api/scenarios/${id}`, { method: "DELETE" });
    await loadScenarios();
  }

  async function handleSaveSettings() {
    setSettingsLoading(true);
    setSettingsMessage(null);

    try {
      const response = await fetch("/api/settings/tibero", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ tiberoConfig: settings }),
      });
      const payload = (await response.json()) as { success: boolean; error?: string };

      if (!payload.success) {
        throw new Error(payload.error ?? "전역 Tibero 설정 저장에 실패했습니다.");
      }

      setSettingsMessage("전역 Tibero 설정을 저장했습니다.");
    } catch (error) {
      setSettingsMessage(error instanceof Error ? error.message : "설정 저장에 실패했습니다.");
    } finally {
      setSettingsLoading(false);
    }
  }

  useEffect(() => {
    void loadScenarios();
    void loadSettings();
  }, []);

  return (
    <main className="px-4 py-8">
      <div className="mb-6 flex items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">테스트 시나리오</h1>
          <p className="text-sm text-muted-foreground">
            시나리오별 테스트 케이스를 저장하고 스냅샷 기준으로 비교합니다.
          </p>
        </div>
        <Link href="/scenarios/new">
          <Button>+ 새 시나리오</Button>
        </Link>
      </div>

      <section className="mb-8 rounded-xl border bg-card p-5">
        <div className="mb-4 flex items-center justify-between gap-4">
          <div>
            <h2 className="text-lg font-semibold">전역 Tibero 설정</h2>
            <p className="text-sm text-muted-foreground">
              여기서 저장한 값은 새 시나리오 작성 시 기본값으로 사용됩니다.
            </p>
          </div>
          <Button disabled={settingsLoading} onClick={handleSaveSettings}>
            {settingsLoading ? "저장 중..." : "설정 저장"}
          </Button>
        </div>

        <div className="grid gap-2 md:grid-cols-2">
          <input
            className="rounded border px-2 py-1 text-sm"
            placeholder="Host"
            value={settings.host}
            onChange={(event) => setSettings({ ...settings, host: event.target.value })}
          />
          <input
            className="rounded border px-2 py-1 text-sm"
            placeholder="Port"
            type="number"
            value={settings.port}
            onChange={(event) =>
              setSettings({ ...settings, port: Number(event.target.value || "0") })
            }
          />
          <input
            className="rounded border px-2 py-1 text-sm"
            placeholder="Username"
            value={settings.username}
            onChange={(event) => setSettings({ ...settings, username: event.target.value })}
          />
          <input
            className="rounded border px-2 py-1 text-sm"
            placeholder="Password"
            type="password"
            value={settings.password}
            onChange={(event) => setSettings({ ...settings, password: event.target.value })}
          />
          <input
            className="rounded border px-2 py-1 text-sm md:col-span-2"
            placeholder="Service Name"
            value={settings.serviceName}
            onChange={(event) => setSettings({ ...settings, serviceName: event.target.value })}
          />
        </div>

        {settingsMessage && <p className="mt-3 text-sm text-blue-700">{settingsMessage}</p>}
      </section>

      {scenarios.length === 0 ? (
        <div className="rounded-xl border border-dashed p-12 text-center text-muted-foreground">
          저장된 시나리오가 없습니다.
        </div>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
          {scenarios.map((scenario) => (
            <ScenarioCard key={scenario.id} scenario={scenario} onDelete={handleDelete} />
          ))}
        </div>
      )}
    </main>
  );
}
